-- Path: game.ReplicatedStorage.Modules.PlotModule
--------------------------------------------------------
game:GetService("ServerScriptService")
local Players = game:GetService("Players")
local v2 = workspace:WaitForChild("Plots"):GetChildren()
local Handlers = {
	["GetEmptyPlot"] = function()
		for _, val3 in v2 do
			if val3:GetAttribute("Owner") == 0 or (not val3:GetAttribute("Owner") or (val3:GetAttribute("Owner") == nil or val3:GetAttribute("Owner") == "")) then
				return val3
			end
		end
		return nil
	end,
	["GetPlotByUserId"] = function(p4)
		for _, val5 in v2 do
			if val5:GetAttribute("Owner") == p4 then
				return val5
			end
		end
		return nil
	end,
	["GetPlotByPlayer"] = function(p6)
		return Handlers.GetPlotByUserId(p6.UserId)
	end,
	["GetPlotByCharacter"] = function(p7)
		local v8 = Players:GetPlayerFromCharacter(p7)
		if v8 then
			return Handlers.GetPlotByPlayer(v8)
		end
	end,
	["GetPlayerByPlot"] = function(p9)
		local v10 = p9:GetAttribute("Owner")
		if v10 then
			return Players:GetPlayerByUserId(v10)
		end
	end,
	["SetOwner"] = function(p11, p12)
		if p12:IsA("Player") then
			p11:SetAttribute("Owner", p12.UserId)
		else
			p11:SetAttribute("Owner", p12)
		end
	end,
	["ClearOwnerByPlayer"] = function(p13)
		local v14 = Handlers.GetPlotByPlayer(p13)
		if v14 then
			v14:SetAttribute("Owner", 0)
		end
	end,
	["ClearOwnerByPlot"] = function(p15)
		p15:SetAttribute("Owner", 0)
	end,
	["RespawnPlayer"] = function(p16)
		if p16 then
			local v17 = Handlers.GetPlotByPlayer(p16)
			if v17 then
				local v18 = p16.Character
				if v18 then
					v18:PivotTo(v17.SpawnLocation.CFrame)
				end
			end
		else
			return
		end
	end
}
return Handlers

