-- Path: game.ReplicatedStorage.Modules.NotificationModule
--------------------------------------------------------
local Module = {}
local TweenService = game:GetService("TweenService")
local Players = game:GetService("Players")
function Module.Show(p4, p5, p6)
	local v7 = p5 or Color3.fromRGB(255, 255, 255)
	local v8 = p6 or 2
	local v9 = Players.LocalPlayer
	local v10
	if v9 then
		v10 = v9.PlayerGui
	else
		v10 = nil
	end
	local v11, v12, v13
	if v10 then
		local v14 = v10:FindFirstChild("Notifications")
		if v14 then
			v11 = v14:FindFirstChild("Frame")
			if v11 then
				v12 = v11:FindFirstChild("Template")
				if v12 then
					v13 = nil
				else
					v11 = nil
					v12 = nil
					v13 = "Template not found"
				end
			else
				v11 = nil
				v12 = nil
				v13 = "Frame not found in Notifications"
			end
		else
			v11 = nil
			v12 = nil
			v13 = "Notifications ScreenGui not found"
		end
	else
		v11 = nil
		v12 = nil
		v13 = "PlayerGui not found"
	end
	if v11 then
		local v15 = v12:Clone()
		local v16 = os.time
		v15.Name = "Notification_" .. tostring(v16())
		v15.Text = p4
		v15.TextColor3 = v7
		v15.Visible = true
		v15.TextTransparency = 1
		v15.TextStrokeTransparency = 1
		local v17 = v15:FindFirstChildOfClass("UIStroke")
		if v17 then
			v17.Transparency = 1
		end
		v15.Parent = v11
		TweenService:Create(v15, TweenInfo.new(0.3), {
			["TextTransparency"] = 0,
			["TextStrokeTransparency"] = 0
		}):Play()
		if v17 then
			TweenService:Create(v17, TweenInfo.new(0.3), {
				["Transparency"] = 0
			}):Play()
		end
		task.delay(v8, function()
			local v18 = TweenService:Create(v15, TweenInfo.new(0.5), {
				["TextTransparency"] = 1,
				["TextStrokeTransparency"] = 1
			})
			v18:Play()
			if v17 then
				TweenService:Create(v17, TweenInfo.new(0.5), {
					["Transparency"] = 1
				}):Play()
			end
			v18.Completed:Wait()
			v15:Destroy()
		end)
		local v19 = {}
		for _, val20 in v11:GetChildren() do
			if val20:IsA("TextLabel") and val20.Name ~= "Template" then
				table.insert(v19, val20)
			end
		end
		if #v19 > 5 then
			table.sort(v19, function(p21, p22)
				return p21.Name < p22.Name
			end)
			for v23 = 1, #v19 - 5 do
				local v24 = v19[v23]
				if v24 then
					v24:Destroy()
				end
			end
		end
	else
		warn("[NotificationModule]", v13)
	end
end
function Module.Success(p25, p26)
	Module.Show(p25, Color3.fromRGB(100, 255, 100), p26)
end
function Module.Error(p27, p28)
	Module.Show(p27, Color3.fromRGB(255, 100, 100), p28)
end
function Module.Warning(p29, p30)
	Module.Show(p29, Color3.fromRGB(255, 200, 100), p30)
end
function Module.Info(p31, p32)
	Module.Show(p31, Color3.fromRGB(100, 200, 255), p32)
end
return Module

