local Players = game:GetService("Players")
game:GetService("TextChatService").OnIncomingMessage = function(p2)
	local v3 = p2.TextSource
	if v3 then
		local v4 = Players:GetPlayerByUserId(v3.UserId)
		if v4 and v4:GetAttribute("HasVIP") == true then
			local v5 = Instance.new("TextChatMessageProperties")
			v5.PrefixText = "<font color=\'#F5CD30\'>[VIP]</font> " .. p2.PrefixText
			return v5
		end
	end
	return nil
end

