	end
	local v34 = p30.steer
	local v35 = p30.throttle
	local v36 = p31 + Vector3.new(v34, 0, v35)
	p30.vehicleSeat.ThrottleFloat = -v36.Z
	p30.vehicleSeat.SteerFloat = v36.X
